import{_ as e,o as l,c as a,a7 as r}from"./chunks/framework.C5fSpjcB.js";const y=JSON.parse('{"title":"召喚システム（ガチャ）","description":"","frontmatter":{},"headers":[],"relativePath":"ja/modes/gacha.md","filePath":"ja/modes/gacha.md","lastUpdated":1775394001000}'),d={name:"ja/modes/gacha.md"};function n(i,t,s,h,o,g){return l(),a("div",null,[...t[0]||(t[0]=[r('<h1 id="召喚システム-ガチャ" tabindex="-1">召喚システム（ガチャ） <a class="header-anchor" href="#召喚システム-ガチャ" aria-label="Permalink to &quot;召喚システム（ガチャ）&quot;">​</a></h1><p>忘却前夜の覚醒体・運命の輪の入手方法である召喚（ガチャ）システムを解説します。</p><h2 id="基本確率" tabindex="-1">基本確率 <a class="header-anchor" href="#基本確率" aria-label="Permalink to &quot;基本確率&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:center;">レアリティ</th><th style="text-align:center;">排出率</th></tr></thead><tbody><tr><td style="text-align:center;"><span class="rarity-ssr">SSR</span></td><td style="text-align:center;"><strong>3%</strong></td></tr><tr><td style="text-align:center;"><span class="rarity-sr">SR</span></td><td style="text-align:center;">15%</td></tr><tr><td style="text-align:center;"><span class="rarity-r">R</span></td><td style="text-align:center;">82%</td></tr></tbody></table><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>v2.0でSSR基礎排出率が1.02%から3%に大幅向上しました。</p></div><h2 id="天井-保証-システム" tabindex="-1">天井（保証）システム <a class="header-anchor" href="#天井-保証-システム" aria-label="Permalink to &quot;天井（保証）システム&quot;">​</a></h2><ul><li><strong>30連（30回召喚）で天井</strong>が発動（v2.0改定、旧v1.xでは80連）</li><li>天井到達時、ピックアップSSR覚醒体が確定入手</li><li>天井カウントはバナーごとに独立（限定池と常驻池は別計算）</li></ul><h3 id="すり抜け救済仕様" tabindex="-1">すり抜け救済仕様 <a class="header-anchor" href="#すり抜け救済仕様" aria-label="Permalink to &quot;すり抜け救済仕様&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:center;">回数</th><th style="text-align:left;">ピックアップ確率</th></tr></thead><tbody><tr><td style="text-align:center;">1回目のSSR</td><td style="text-align:left;">33.33%がピックアップ対象</td></tr><tr><td style="text-align:center;">2回目のSSR（1回目すり抜け時）</td><td style="text-align:left;">66.66%がピックアップ対象</td></tr><tr><td style="text-align:center;">3回目のSSR（2回目もすり抜け時）</td><td style="text-align:left;">**100%**ピックアップ確定</td></tr></tbody></table><p>最大120連（4回の30連サイクル）以内にピックアップキャラが確定入手できます。また、同じピックアップ対象が2回連続で出た場合、次回は別のピックアップ対象が確定します。</p><h2 id="バナーの種類" tabindex="-1">バナーの種類 <a class="header-anchor" href="#バナーの種類" aria-label="Permalink to &quot;バナーの種類&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">バナー</th><th style="text-align:center;">通貨</th><th style="text-align:left;">特徴</th></tr></thead><tbody><tr><td style="text-align:left;">灵识黒潮（常驻池）</td><td style="text-align:center;">無垢之芯</td><td style="text-align:left;">常驻SSRキャラ池。UP機制なし。30連保底SSR。5回唤醒でSSR+運命の輪保底</td></tr><tr><td style="text-align:left;">限定活動唤醒（限定池）</td><td style="text-align:center;">流明之芯</td><td style="text-align:left;">新限定キャラ初登場池。限定SSRは常驻に入らない</td></tr><tr><td style="text-align:left;">万華追憶（限定専属池）</td><td style="text-align:center;">流明之芯</td><td style="text-align:left;">純限定キャラ池。常驻SSRを含まない。30連以内に限定SSRキャラまたは運命の輪を保底</td></tr><tr><td style="text-align:left;">復刻池</td><td style="text-align:center;">流明之芯</td><td style="text-align:left;">過去の限定キャラ復刻</td></tr><tr><td style="text-align:left;">必得唤醒（課金保底池）</td><td style="text-align:center;">源液x980/回</td><td style="text-align:left;">5回で限定SSRキャラ2体+限定SSR運命の輪3本を保底。旧世篇/星辰篇・男/女子池に分類</td></tr><tr><td style="text-align:left;">自選唤醒</td><td style="text-align:center;">各種</td><td style="text-align:left;">イベント限定。SSRキャラ1体+専属運命の輪をUP対象として自選可能</td></tr></tbody></table><h2 id="召喚通貨" tabindex="-1">召喚通貨 <a class="header-anchor" href="#召喚通貨" aria-label="Permalink to &quot;召喚通貨&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">通貨</th><th style="text-align:left;">用途</th><th style="text-align:left;">入手方法</th></tr></thead><tbody><tr><td style="text-align:left;">源液 (Silver Prime)</td><td style="text-align:left;">課金通貨。必得唤醒等に使用</td><td style="text-align:left;">課金購入</td></tr><tr><td style="text-align:left;">銀芯 (Silver Core)</td><td style="text-align:left;">主要無課金通貨。流明之芯・無垢之芯に交換（約200銀芯=1回分）</td><td style="text-align:left;">デイリーミッション、メインステージ評価（100/関）、手帳、幻夢深潜、イベント、通行証、交換コード</td></tr><tr><td style="text-align:left;">流明之芯 (Lumen Core)</td><td style="text-align:left;">限定池召喚通貨（1個=1回）。入手手段が限られるため優先交換推奨</td><td style="text-align:left;">銀芯交換、イベント報酬、通行証</td></tr><tr><td style="text-align:left;">無垢之芯 (Pure Core)</td><td style="text-align:left;">常驻池召喚通貨（1個=1回）</td><td style="text-align:left;">銀芯交換、イベント報酬、キャラ初回昇格、通行証無料トラック（40個）、チャプター初通関</td></tr><tr><td style="text-align:left;">沈澱幣 (Sediment Currency)</td><td style="text-align:left;">召喚副産物。沈澱ショップで素材交換</td><td style="text-align:left;">唤醒時の副産物</td></tr></tbody></table><h2 id="召喚の心得" tabindex="-1">召喚の心得 <a class="header-anchor" href="#召喚の心得" aria-label="Permalink to &quot;召喚の心得&quot;">​</a></h2><div class="warning custom-block"><p class="custom-block-title">WARNING</p><p><span class="server-badge server-jp">JP</span> JPサーバーの実装順序はCNサーバーと異なる場合があります。今後実装予定のキャラクターを見越して通貨を温存するのも戦略の一つです。</p></div><ol><li><strong>天井分の通貨を確保してから引く</strong> — 30連分を貯めてからガチャに臨む</li><li><strong>ピックアップを狙う</strong> — 恒常ガチャより期間限定ピックアップの方が効率的</li><li><strong>運命の輪は余裕がある時に</strong> — キャラクター優先。装備は後から入手手段がある</li><li><strong>啓霊は計画的に</strong> — 完凸を狙うか、新キャラを広く集めるか方針を決める</li><li><strong>常驻池はキャラ池優先</strong> — 無垢之芯でまずキャラ池を回し、核心キャラを確保</li><li><strong>F2Pプレイヤーは24を最優先</strong> — 次いで墨菲を確保</li></ol><h2 id="新規プレイヤー向け召喚福利" tabindex="-1">新規プレイヤー向け召喚福利 <a class="header-anchor" href="#新規プレイヤー向け召喚福利" aria-label="Permalink to &quot;新規プレイヤー向け召喚福利&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">条件</th><th style="text-align:left;">報酬</th></tr></thead><tbody><tr><td style="text-align:left;">開始時</td><td style="text-align:left;">銀芯1500（約7連分）+ 常驻池15連分</td></tr><tr><td style="text-align:left;">累計ログイン7日</td><td style="text-align:left;">イベント池10連分</td></tr><tr><td style="text-align:left;">アカウントLv.35到達</td><td style="text-align:left;">常驻池最大40連分 + 銀芯2000（10連分）</td></tr><tr><td style="text-align:left;">累計ログイン3日・7日</td><td style="text-align:left;">各1回の常驻SSR自選</td></tr><tr><td style="text-align:left;">累計召喚50回</td><td style="text-align:left;">常驻SSR自選1回</td></tr></tbody></table><p>7日後には最低でも3体以上のSSRキャラクターを所持できます。</p><h2 id="関連ページ" tabindex="-1">関連ページ <a class="header-anchor" href="#関連ページ" aria-label="Permalink to &quot;関連ページ&quot;">​</a></h2><ul><li><a href="./../awakeners/list.html">覚醒体一覧</a></li><li><a href="./../wheels/list.html">運命の輪一覧</a></li><li><a href="./../awakeners/enlightenment.html">啓霊システム</a></li><li><a href="./../items/currency.html">通貨一覧</a></li><li><a href="./../guides/beginner.html">初心者ガイド</a></li></ul>',22)])])}const c=e(d,[["render",n]]);export{y as __pageData,c as default};
